SELECT
    dss.summary_date as summaryDate,
    dss.total_orders as totalOrders,
    dss.total_revenue as totalRevenue,
    dss.avg_order_value as avgOrderValue,
    dss.currency as currency
FROM daily_sales_summary dss

    AND dss.summary_date = #{summaryDate}
    AND dss.currency = #{currency}
    AND dss.summary_date >= #{startDate}
    AND dss.summary_date <= #{endDate}

${orderby} ${pagination}

SELECT count(*)
FROM daily_sales_summary dss

    AND dss.summary_date = #{summaryDate}
    AND dss.currency = #{currency}
    AND dss.summary_date >= #{startDate}
    AND dss.summary_date <= #{endDate}

SELECT
    pp.product_id as productId,
    pp.period_date as periodDate,
    pp.views as views,
    pp.purchases as purchases,
    pp.revenue as revenue,
    pp.avg_rating as avgRating
FROM product_performance pp

    AND pp.product_id = #{productId}
    AND pp.period_date >= #{startDate}
    AND pp.period_date <= #{endDate}

${orderby} ${pagination}

SELECT count(*)
FROM product_performance pp

    AND pp.product_id = #{productId}
    AND pp.period_date >= #{startDate}
    AND pp.period_date <= #{endDate}
